import { Mastra } from 'mastra';
import { VexClient } from '@vex_dev/sdk';

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  project: 'my-mastra-agent',
  environment: process.env.NODE_ENV ?? 'development',
});

export { vex };

import { createTool } from 'mastra';
import { z } from 'zod';
import { vex } from './vex-client';

const stripeChargeSchema = z.object({
  charge_id: z.string(),
  amount: z.number(),
  currency: z.string(),
  status: z.enum(['succeeded', 'pending', 'failed']),
});

export const stripeChargeTool = createTool({
  id: 'stripe-get-charge',
  description: 'Retrieves a Stripe charge by ID',
  inputSchema: z.object({ chargeId: z.string() }),
  outputSchema: stripeChargeSchema,
  execute: vex.wrapTool(
    async ({ context }) => {
      const response = await fetch(
        `https://api.stripe.com/v1/charges/${context.chargeId}`,
        { headers: { Authorization: `Bearer ${process.env.STRIPE_KEY}` } }
      );
      if (!response.ok) {
        throw new Error(`Stripe API error: ${response.status}`);
      }
      return response.json();
    },
    {
      toolId: 'stripe-get-charge',
      outputSchema: stripeChargeSchema,
      onViolation: 'throw',
    }
  ),
});

import { createWorkflow, createStep } from 'mastra';
import { z } from 'zod';
import { vex } from './vex-client';

const userSchema = z.object({
  id: z.string(),
  email: z.string().email(),
  plan: z.enum(['free', 'pro', 'enterprise']),
});

const reportSchema = z.object({
  userId: z.string(),
  reportUrl: z.string().url(),
  generatedAt: z.string().datetime(),
});

const fetchUserStep = createStep({
  id: 'fetch-user',
  inputSchema: z.object({ userId: z.string() }),
  outputSchema: userSchema,
  execute: vex.wrapStep(
    async ({ inputData }) => {
      const user = await db.users.findById(inputData.userId);
      if (!user) throw new Error(`User ${inputData.userId} not found`);
      return user;
    },
    { stepId: 'fetch-user', outputSchema: userSchema }
  ),
});

const generateReportStep = createStep({
  id: 'generate-report',
  inputSchema: userSchema,
  outputSchema: reportSchema,
  execute: vex.wrapStep(
    async ({ inputData }) => {
      const url = await reportService.generate(inputData.id, inputData.plan);
      return {
        userId: inputData.id,
        reportUrl: url,
