  ),
});

export const reportWorkflow = createWorkflow({
  name: 'generate-user-report',
  triggerSchema: z.object({ userId: z.string() }),
})
  .then(fetchUserStep)
  .then(generateReportStep)
  .commit();

import { Agent } from 'mastra';
import { vex } from './vex-client';
import { stripeChargeTool } from './tools/stripe';

const billingAgent = new Agent({
  name: 'billing-agent',
  instructions: 'You help users understand their billing history and resolve charge disputes.',
  model: {
    provider: 'OPEN_AI',
    toolChoice: 'auto',
    name: 'gpt-4o',
  },
  tools: { stripeChargeTool },
});

// Wrap the agent's generate method with Vex memory and context guards
const safeBillingAgent = vex.wrapAgent(billingAgent, {
  agentId: 'billing-agent',
  memoryGuard: {
    enabled: true,
    stalenessThresholdMs: 24 * 60 * 60 * 1000, // 24 hours
    onStaleRecord: 'warn-and-filter',
  },
  contextGuard: {
    enabled: true,
    maxContextTokens: 8000,
    onOverflow: 'truncate-oldest',
  },
  integrationGuard: {
    enabled: true,
    syncConflictStrategy: 'prefer-remote',
    onConflict: (conflict) => {
      console.warn('[Vex] Sync conflict detected:', conflict);
    },
  },
});

// Use safeBillingAgent.generate() exactly like billingAgent.generate()
export { safeBillingAgent };
